#!/usr/bin/env node
// Splits the deployer wallet's mainnet ETH evenly across the 10 collector
// wallets generated by generate.js. Reads the deployer's key straight out of
// agents/wallets/deployer.mcp.json (never printed) and the collector
// addresses out of agents/wallets/manifest.json — nothing to paste.
//
// SAFE BY DEFAULT: prints the exact plan and sends NOTHING unless you pass
// --send. Run it once without --send first, review the numbers, then run it
// again with --send to actually broadcast. This script is meant to be run
// BY YOU — it is deliberately never invoked by the assistant.
//
// Usage:
//   node agents/fund-collectors.js                # dry run (default, mainnet)
//   node agents/fund-collectors.js --send          # actually sends
//   node agents/fund-collectors.js --reserve 0.001 # leave more in deployer
//   node agents/fund-collectors.js --testnet       # target testnet (46630) instead
import { ethers } from 'ethers';
import { readFileSync } from 'fs';
import { fileURLToPath } from 'url';
import path from 'path';

const here = path.dirname(fileURLToPath(import.meta.url));
const walletsDir = path.join(here, 'wallets');

const args = process.argv.slice(2);
const SEND = args.includes('--send');
const TESTNET = args.includes('--testnet');
const reserveIdx = args.indexOf('--reserve');
const RESERVE_ETH = reserveIdx >= 0 ? Number(args[reserveIdx + 1]) : 0.0005; // headroom for the deployer's own future gas

const RPC = TESTNET ? 'https://rpc.testnet.chain.robinhood.com' : 'https://rpc.mainnet.chain.robinhood.com';
const CHAIN_ID = TESTNET ? 46630 : 4663;

const deployerConfig = JSON.parse(readFileSync(path.join(walletsDir, 'deployer.mcp.json'), 'utf8'));
const deployerKey = Object.values(deployerConfig.mcpServers)[0].env.SAGE_AGENT_PRIVATE_KEY;
const manifest = JSON.parse(readFileSync(path.join(walletsDir, 'manifest.json'), 'utf8'));
const collectors = manifest.filter((a) => a.role === 'collector');

const provider = new ethers.providers.StaticJsonRpcProvider(RPC, CHAIN_ID);
// same legacy-gas-pricing fix as chain.js: this chain's real gas price is
// ~0.05-0.1 gwei, but ethers' default EIP-1559 estimate inflates
// maxFeePerGas ~150x via a 1.5 gwei priority fee, which can make a
// lightly-funded send look like it needs way more than it does.
const _getGasPrice = provider.getGasPrice.bind(provider);
provider.getFeeData = async () => {
  const gasPrice = await _getGasPrice();
  return { gasPrice, maxFeePerGas: null, maxPriorityFeePerGas: null, lastBaseFeePerGas: null };
};

const deployer = new ethers.Wallet(deployerKey, provider);

// eth_gasPrice is a suggested value, not a guarantee it clears whatever the
// CURRENT block's base fee is by the time a tx actually lands — on a chain
// this cheap, base fee can drift past a just-fetched price within seconds
// (hit this for real: quoted 0.065592 gwei, chain had moved to 0.06737 gwei
// base fee by broadcast time, node rejected pre-inclusion — no funds lost,
// just a rejected send). Fix: always refetch immediately before each send
// AND pad it, since the padding costs nothing in absolute terms here.
const GAS_PRICE_BUFFER_PCT = 150; // 1.5x whatever eth_gasPrice reports
async function bufferedGasPrice() {
  return (await provider.getGasPrice()).mul(GAS_PRICE_BUFFER_PCT).div(100);
}

// Hit a second, different rejection on a real run: "intrinsic gas too low"
// on collector-7 even though collector-1..6 sent fine with the textbook
// 21000 gas limit for a plain transfer. Rather than guess a bigger constant,
// ask the node what it actually wants and pad it — cheap here regardless.
async function bufferedGasLimit(tx) {
  const estimate = await provider.estimateGas(tx);
  return estimate.mul(130).div(100);
}

// Dust threshold for "already funded" — lets a re-run after a partial
// failure skip collectors that got their share in an earlier attempt
// instead of sending them a second helping.
const ALREADY_FUNDED_THRESHOLD = ethers.utils.parseEther('0.0001');

(async () => {
  // Check who's already funded FIRST — a re-run after a partial failure
  // (some collectors succeeded, one rejected) should split the remaining
  // balance across only the remaining recipients, not divide by all 10 and
  // shortchange whoever's left.
  const balances = await Promise.all(collectors.map((c) => provider.getBalance(c.address)));
  const pending = collectors.filter((_, i) => balances[i].lt(ALREADY_FUNDED_THRESHOLD));
  const alreadyFunded = collectors.filter((_, i) => balances[i].gte(ALREADY_FUNDED_THRESHOLD));

  const balanceWei = await provider.getBalance(deployer.address);
  const balance = Number(ethers.utils.formatEther(balanceWei));
  const gasPrice = await bufferedGasPrice();
  const gasPerSendEth = Number(ethers.utils.formatEther(gasPrice.mul(21000)));
  const totalGasEth = gasPerSendEth * pending.length;

  console.log(`deployer:        ${deployer.address}`);
  console.log(`balance:         ${balance} ETH`);
  console.log(`gas price:       ${ethers.utils.formatUnits(gasPrice, 'gwei')} gwei`);
  console.log(`reserve kept:    ${RESERVE_ETH} ETH`);
  if (alreadyFunded.length) {
    console.log(`already funded:  ${alreadyFunded.map((c) => c.name).join(', ')} (skipping)`);
  }

  if (pending.length === 0) {
    console.log('\nEveryone is already funded — nothing to do.');
    return;
  }

  const distributable = balance - RESERVE_ETH - totalGasEth;
  if (distributable <= 0) {
    console.error(
      `Not enough to distribute: balance ${balance} ETH, reserve ${RESERVE_ETH}, ` +
        `est. gas for ${pending.length} sends ${totalGasEth.toFixed(8)} ETH.`
    );
    process.exit(1);
  }
  const perWallet = distributable / pending.length;
  const perWalletWei = ethers.utils.parseEther(perWallet.toFixed(18));

  console.log(`est. total gas:  ${totalGasEth.toFixed(8)} ETH (${pending.length} sends)`);
  console.log(`per collector:   ${perWallet.toFixed(8)} ETH`);
  console.log(`recipients:      ${pending.length} (${pending.map((c) => c.name).join(', ')})`);
  console.log(`mode:            ${SEND ? 'SENDING FOR REAL' : 'DRY RUN — nothing will be sent'}\n`);

  for (const c of pending) {
    if (!SEND) {
      console.log(`  [dry-run] would send ${perWallet.toFixed(8)} ETH -> ${c.name} (${c.address})`);
      continue;
    }
    // fresh + buffered gasPrice/gasLimit EVERY send (not values from the top
    // of the run) — explicit gasPrice/gasLimit forces an unambiguous legacy
    // tx instead of depending on ethers' internal fee-resolution picking up
    // the provider.getFeeData patch, and a real gas estimate instead of the
    // textbook 21000 (which this chain rejected once as "too low").
    const sendGasPrice = await bufferedGasPrice();
    const txRequest = { to: c.address, value: perWalletWei };
    const sendGasLimit = await bufferedGasLimit(txRequest);
    const tx = await deployer.sendTransaction({
      ...txRequest,
      gasPrice: sendGasPrice,
      gasLimit: sendGasLimit,
    });
    console.log(`  sending ${perWallet.toFixed(8)} ETH -> ${c.name} (${c.address}) ... ${tx.hash}`);
    await tx.wait(1);
    console.log(`    confirmed`);
  }

  if (!SEND) {
    console.log('\nDry run only — re-run with --send to actually broadcast these transactions.');
  } else {
    console.log('\nDone.');
  }
})().catch((e) => {
  console.error('FAILED:', e.message);
  process.exit(1);
});
